# subscriptions.tf
variable "subscriptions" {
  type = map(object({
    display_name              = string
    billing_scope_id          = string
    workload                  = string # Production | DevTest
    strategy_tier             = string
    owner_group_object_id     = string
    cost_center               = string
    monthly_budget            = number
    requires_network          = bool
  }))
}

resource "azurerm_subscription" "vended" {
  for_each          = var.subscriptions
  subscription_name = each.key
  billing_scope_id  = each.value.billing_scope_id
  workload          = each.value.workload
  tags = {
    cost-center = each.value.cost_center
    managed-by  = "platform"
  }
}

resource "azurerm_management_group_subscription_association" "vended" {
  for_each = var.subscriptions
  management_group_id = var.management_group_ids[each.value.strategy_tier]
  subscription_id     = "/subscriptions/${azurerm_subscription.vended[each.key].subscription_id}"
}

resource "azurerm_role_assignment" "vended_owner" {
  for_each             = var.subscriptions
  scope                = "/subscriptions/${azurerm_subscription.vended[each.key].subscription_id}"
  role_definition_name = "Owner"
  principal_id         = each.value.owner_group_object_id
}

resource "azurerm_consumption_budget_subscription" "vended" {
  for_each        = var.subscriptions
  name            = "monthly-budget"
  subscription_id = "/subscriptions/${azurerm_subscription.vended[each.key].subscription_id}"
  amount          = each.value.monthly_budget
  time_grain      = "Monthly"
  time_period {
    start_date = "2026-07-01T00:00:00Z"
    end_date   = "2027-07-01T00:00:00Z"
  }
  notification {
    enabled        = true
    operator       = "GreaterThan"
    threshold      = 80
    contact_emails = ["platform@example.com"]
  }
}

